const params = $input.item.json.params || {};
const token = params.token || $input.item.json.token || '';
if (!token || token.length < 8) return { json: { _bad_token: true } };
return { json: { token: token } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? rows[0] : rows;
if (!row || !row.id || row.status !== 'ready' && row.status !== 'delivered') {
  return { json: { _not_found: true } };
}
return { json: { render: row } };

// Render personalised landing page HTML.
const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    return items;
  } catch (e) { return []; }
};
const leads = allOf('Fetch Lead');
const clients = allOf('Fetch Client');
const lead = leads[0] || {};
const client = clients[0] || {};
const render = $('Validate Render').item.json.render;

const escape = function (s) { return String(s == null ? '' : s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;').replace(/'/g, '&#39;'); };
const firstName = escape(lead.first_name || (lead.full_name || '').split(' ')[0] || 'there');
const company = escape(lead.company || 'your business');
const clientName = escape(client.client_name || 'Crystallux');
const videoUrl = escape(render.storage_url);
const bookUrl = escape(client.calendly_url || ('https://crystallux.org/book?lead=' + encodeURIComponent(lead.id || '')));
const trackerBase = process.env.LANDING_PAGE_TRACKER_BASE || 'https://automation.crystallux.org/webhook/v/track';
const renderId = escape(render.id);

const html = [
  '<!doctype html>',
  '<html lang="en">',
  '<head>',
  '  <meta charset="utf-8" />',
  '  <meta name="viewport" content="width=device-width,initial-scale=1" />',
  '  <title>A quick personal video for ' + firstName + '</title>',
  '  <style>',
  '    *{box-sizing:border-box;margin:0;padding:0}',
  '    body{font-family:Inter,-apple-system,system-ui,Segoe UI,Roboto,sans-serif;background:linear-gradient(180deg,#0F0A1F 0%,#1F1338 100%);color:#fff;min-height:100vh;padding:24px 16px}',
  '    .wrap{max-width:720px;margin:0 auto;padding:32px 0}',
  '    .brand{display:flex;align-items:center;gap:8px;font-size:14px;opacity:.7;margin-bottom:24px}',
  '    .brand-dot{width:14px;height:14px;border-radius:50%;background:linear-gradient(135deg,#7C3AED 0%,#5B21B6 100%)}',
  '    h1{font-size:28px;line-height:1.2;font-weight:600;margin-bottom:12px}',
  '    h1 .accent{color:#A78BFA}',
  '    .lede{font-size:16px;opacity:.85;margin-bottom:24px;line-height:1.5}',
  '    .video-wrap{background:#000;border-radius:16px;overflow:hidden;box-shadow:0 20px 60px rgba(124,58,237,.25);margin-bottom:24px;aspect-ratio:16/9}',
  '    video{width:100%;height:100%;display:block}',
  '    .cta{display:block;width:100%;padding:18px 24px;background:linear-gradient(135deg,#7C3AED 0%,#5B21B6 100%);color:#fff;text-decoration:none;border-radius:12px;text-align:center;font-weight:600;font-size:18px;box-shadow:0 8px 24px rgba(124,58,237,.4);transition:transform .15s}',
  '    .cta:hover{transform:translateY(-2px)}',
  '    .footer{text-align:center;font-size:13px;opacity:.55;margin-top:32px}',
  '    @media (max-width:480px){h1{font-size:22px}}',
  '  </style>',
  '</head>',
  '<body>',
  '  <div class="wrap">',
  '    <div class="brand"><span class="brand-dot"></span><span>' + clientName + '</span></div>',
  '    <h1>Hey <span class="accent">' + firstName + '</span> — quick video for ' + company + '</h1>',
  '    <p class="lede">Takes 60 seconds. Tap to unmute.</p>',
  '    <div class="video-wrap">',
  '      <video id="v" src="' + videoUrl + '" controls autoplay muted playsinline preload="metadata"></video>',
  '    </div>',
  '    <a class="cta" id="cta" href="' + bookUrl + '" target="_blank" rel="noopener">Book 15 minutes &rarr;</a>',
  '    <p class="footer">Powered by ' + clientName + ' &middot; <a href="https://crystallux.org" style="color:inherit">Crystallux</a></p>',
  '  </div>',
  '  <script>',
  '    (function(){',
  '      var rid="' + renderId + '";',
  '      var trk="' + trackerBase + '";',
  '      function send(t,d){fetch(trk,{method:"POST",headers:{"content-type":"application/json"},body:JSON.stringify({video_render_id:rid,event_type:t,event_data:d||{}})}).catch(function(){});}',
  '      send("page_view");',
  '      var v=document.getElementById("v");',
  '      var seen={p:false,q1:false,q2:false,q3:false,c:false};',
  '      v.addEventListener("play",function(){if(!seen.p){send("video_play");seen.p=true;}});',
  '      v.addEventListener("timeupdate",function(){',
  '        var p=v.currentTime/(v.duration||1);',
  '        if(p>=.25&&!seen.q1){send("video_25");seen.q1=true;}',
  '        if(p>=.50&&!seen.q2){send("video_50");seen.q2=true;}',
  '        if(p>=.75&&!seen.q3){send("video_75");seen.q3=true;}',
  '      });',
  '      v.addEventListener("ended",function(){if(!seen.c){send("video_complete");seen.c=true;}});',
  '      document.getElementById("cta").addEventListener("click",function(){send("cta_click");});',
  '    })();',
  '  </script>',
  '</body>',
  '</html>'
].join('\n');

return { json: { html: html, status: 200 } };
